import sys
from collections import defaultdict

MOD = 998244353

def main():
    n, k = map(int, sys.stdin.readline().split())
    digits = list(map(int, sys.stdin.readline().split()))

    m = n // 2
    max_sum = 9 * m

    # Precompute frequency of each digit
    freq = defaultdict(int)
    for d in digits:
        freq[d] += 1

    # Initialize dp for single digit
    dp = [0] * (max_sum + 1)
    for d in digits:
        if d <= max_sum:
            dp[d] += 1

    # Iterate for m-1 more digits
    for _ in range(1, m):
        new_dp = [0] * (max_sum + 1)
        for s in range(max_sum + 1):
            if dp[s] == 0:
                continue
            for d in digits:
                if s + d <= max_sum:
                    new_dp[s + d] = (new_dp[s + d] + dp[s]) % MOD
        dp = new_dp

    total = 0
    for s in range(max_sum + 1):
        total = (total + dp[s] * dp[s]) % MOD

    print(total)

if __name__ == "__main__":
    main()
